        # format query string based on different operators
        if operator == '>':
            query += " %s> :%s" % (field_name, field_name)
        elif operator == '<':
            query += " %s< :%s" % (field_name, field_name)
        else:
            query += " %s= :%s" % (field_name, field_name)

        # increment index for next query part
        i += 1

